func:
if (!msg.garminEmail || msg.garminEmail === 'YOUR_EMAIL@EXAMPLE.COM') {
    node.warn('Set garminEmail in the Setup inject node.');
    return null;
}
if (!msg.garminPassword || msg.garminPassword === 'YOUR_GARMIN_PASSWORD') {
    node.warn('Set garminPassword in the Setup inject node.');
    return null;
}
if (!msg.scriptPath || msg.scriptPath.indexOf('/path/to/') !== -1) {
    node.warn('Set scriptPath to the full path of garmin-fetch.js in the Setup inject node.');
    return null;
}
flow.set('vaultPath', msg.vaultPath);
flow.set('scriptPath', msg.scriptPath);
msg.payload = JSON.stringify({ email: msg.garminEmail, password: msg.garminPassword }, null, 2);
msg.filename = msg.configFilePath;
node.status({ fill: 'green', shape: 'dot', text: 'Config written to ' + msg.configFilePath });
return msg;

const scriptPath = flow.get('scriptPath');
if (!scriptPath) { node.warn('Run the Setup inject first.'); return null; }
let date;
if (msg.manualDate) {
    date = msg.manualDate;
} else {
    // Use system local time — yesterday relative to when this runs
    const now = new Date();
    const yest = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1);
    const yyyy = String(yest.getFullYear());
    const mm = String(yest.getMonth() + 1).padStart(2, '0');
    const dd = String(yest.getDate()).padStart(2, '0');
    date = yyyy + '-' + mm + '-' + dd;
}
node.warn('garmin daily → date: ' + date);
const parts = date.split('-');
msg.garminDate = date;
msg.dateStr = { year: parts[0], month: parts[1], day: parts[2] };
msg.files = { dailynotefile: date + '.md' };
msg._isHistoric = false;
msg.payload = scriptPath + ' --type daily --date ' + date;
return msg;

const raw = (msg.payload || '').trim();
if (!raw) {
    node.warn('garmin-fetch: no stdout. Check Exec Error debug for stderr.');
    return null;
}
let data;
try { data = JSON.parse(raw); } catch(e) {
    node.warn('garmin-fetch JSON parse error: ' + raw.substring(0, 200));
    return null;
}
msg.sleepData    = data.sleep    || {};
msg.hrData       = data.hr       || {};
msg.wellnessData = data.wellness || {};
msg.weightData   = data.weight   || null;
msg.bpData       = data.bp       || null;
return msg;

const scriptPath = flow.get('scriptPath');
if (!scriptPath) { node.warn('Run the Setup inject first.'); return null; }
// Runs Monday 02:00 local — sunday = yesterday, monday = 6 days before that
const today = new Date();
const sunday = new Date(today.getFullYear(), today.getMonth(), today.getDate() - 1);
const monday = new Date(today.getFullYear(), today.getMonth(), today.getDate() - 7);
const fmt = function(d) {
    return d.getFullYear() + '-'
        + String(d.getMonth() + 1).padStart(2, '0') + '-'
        + String(d.getDate()).padStart(2, '0');
};
msg.weekStart = fmt(monday);
msg.weekEnd   = fmt(sunday);
const yyyy = String(sunday.getFullYear());
const mm = String(sunday.getMonth() + 1).padStart(2, '0');
const dd = String(sunday.getDate()).padStart(2, '0');
msg.garminDate = yyyy + '-' + mm + '-' + dd;
msg.dateStr = { year: yyyy, month: mm, day: dd };
msg.files = { dailynotefile: yyyy + '-' + mm + '-' + dd + '.md' };
const jan1 = new Date(sunday.getFullYear(), 0, 1);
const weekNum = Math.ceil(((sunday - jan1) / 86400000 + jan1.getDay() + 1) / 7);
msg.weekLabel = 'W' + String(weekNum).padStart(2, '0');
msg._isHistoric = false;
msg.payload = scriptPath + ' --type weekly --weekStart ' + msg.weekStart + ' --weekEnd ' + msg.weekEnd;
return msg;

const raw = (msg.payload || '').trim();
if (!raw) {
    return [null, { payload: 'No output from script (check Exec Error debug)' }];
}
let data;
try { data = JSON.parse(raw); } catch(e) {
    return [null, { payload: 'Parse error: ' + raw.substring(0, 200) }];
}
if (!data.stats || data.stats.count === 0) {
    return [null, { payload: 'No cycling rides ' + msg.weekStart + '\u2013' + msg.weekEnd }];
}
msg.weeklyStats = data.stats;
return [msg, null];

const st = msg.weeklyStats;
function fmtDur(s) {
    const h = Math.floor(s / 3600);
    const m = String(Math.floor((s % 3600) / 60)).padStart(2, '0');
    return h + 'h ' + m + 'm';
}
const dedupId = 'garmin-weekly-' + msg.garminDate + '-' + msg.weekLabel;
msg.noteupdate = [
    '- \uD83D\uDEB4 Weekly Cycling ' + msg.weekLabel + ' #garmin',
    '  <!-- ' + dedupId + ' -->',
    '\t- **Distance:** ' + (st.distanceM / 1000).toFixed(1) + ' km'
        + ' | **Rides:** ' + st.count
        + ' | **Elevation:** ' + Math.round(st.elevationM) + ' m'
        + ' | **Time:** ' + fmtDur(st.movingSecs)
].join('\n');
msg.dedupId = dedupId;
return msg;

const vaultPath = flow.get('vaultPath') || '/kms/10 PMS/11 Daily Notes';
msg.filename = vaultPath
    + '/' + msg.dateStr.year
    + '/' + msg.dateStr.month
    + '/' + msg.files.dailynotefile;
return msg;

// Guard: don't re-init if cursor already set (mid-iteration)
if (msg._historicCurrent) {
    msg._isHistoric = true;
    return msg;
}
if (!msg.historyYear) { node.warn('historyYear not set on inject node.'); return null; }
const scriptPath = flow.get('scriptPath');
if (!scriptPath) { node.warn('Run the Setup inject first.'); return null; }
const year = Number(msg.historyYear);
msg._historicStart   = Date.UTC(year, 0, 1);
msg._historicEnd     = Date.UTC(year, 11, 31);
msg._historicCurrent = Date.UTC(year, 0, 1);
msg._isHistoric = true;
const d = new Date(msg._historicCurrent);
const yyyy = String(d.getUTCFullYear());
const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
const dd = String(d.getUTCDate()).padStart(2, '0');
msg.garminDate = yyyy + '-' + mm + '-' + dd;
msg.dateStr = { year: yyyy, month: mm, day: dd };
msg.files = { dailynotefile: yyyy + '-' + mm + '-' + dd + '.md' };
node.status({ text: 'Starting ' + year });
return msg;

const scriptPath = flow.get('scriptPath');
msg.payload = scriptPath + ' --type daily --date ' + msg.garminDate;
return msg;

const raw = (msg.payload || '').trim();
if (!raw) {
    node.warn('No output for ' + msg.garminDate + ' — skipping');
    return [null, msg];  // out2 → skip to next day
}
let data;
try { data = JSON.parse(raw); } catch(e) {
    node.warn('Parse error for ' + msg.garminDate + ': ' + raw.substring(0, 200));
    return [null, msg];  // out2 → skip to next day
}
msg.sleepData    = data.sleep    || {};
msg.hrData       = data.hr       || {};
msg.wellnessData = data.wellness || {};
msg.weightData   = data.weight   || null;
return [msg, null];

msg._historicCurrent += 86400000;
if (msg._historicCurrent > msg._historicEnd) {
    node.status({ fill: 'green', shape: 'dot', text: 'Done: ' + msg.historyYear });
    return [null, { payload: 'Historic load done: ' + msg.historyYear }];
}
const d = new Date(msg._historicCurrent);
const yyyy = String(d.getUTCFullYear());
const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
const dd = String(d.getUTCDate()).padStart(2, '0');
msg.garminDate = yyyy + '-' + mm + '-' + dd;
msg.dateStr = { year: yyyy, month: mm, day: dd };
msg.files = { dailynotefile: yyyy + '-' + mm + '-' + dd + '.md' };
const total   = Math.round((msg._historicEnd   - msg._historicStart) / 86400000) + 1;
const current = Math.round((msg._historicCurrent - msg._historicStart) / 86400000) + 1;
node.status({ text: msg.garminDate + ' (' + current + '/' + total + ')' });
return [msg, null];

const sl = msg.sleepData    || {};
const hr = msg.hrData       || {};
const wl = msg.wellnessData || {};
const wt = msg.weightData   || null;

msg.garminProps = {};
if (wl.totalSteps)                    msg.garminProps.garmin_steps = wl.totalSteps;
if (sl.durationSeconds)               msg.garminProps.garmin_sleep_hours = +(sl.durationSeconds / 3600).toFixed(1);
if (sl.sleepScore)                    msg.garminProps.garmin_sleep_score = sl.sleepScore;
if (sl.deepSleepSeconds)              msg.garminProps.garmin_sleep_deep_min = Math.round(sl.deepSleepSeconds / 60);
if (sl.lightSleepSeconds)             msg.garminProps.garmin_sleep_light_min = Math.round(sl.lightSleepSeconds / 60);
if (sl.remSleepSeconds)               msg.garminProps.garmin_sleep_rem_min = Math.round(sl.remSleepSeconds / 60);
if (sl.awakeSleepSeconds)             msg.garminProps.garmin_sleep_awake_min = Math.round(sl.awakeSleepSeconds / 60);
if (sl.bodyBatteryChange != null)     msg.garminProps.garmin_body_battery_sleep = sl.bodyBatteryChange;
if (hr.restingHR)                     msg.garminProps.garmin_hr_resting = hr.restingHR;
if (hr.maxHR)                         msg.garminProps.garmin_hr_max = hr.maxHR;
if (wl.averageStressLevel)            msg.garminProps.garmin_stress = wl.averageStressLevel;
if (wl.moderateIntensityMinutes)      msg.garminProps.garmin_intensity_moderate = wl.moderateIntensityMinutes;
if (wl.vigorousIntensityMinutes)      msg.garminProps.garmin_intensity_vigorous = wl.vigorousIntensityMinutes;
const totalIntensity = (wl.moderateIntensityMinutes || 0) + 2 * (wl.vigorousIntensityMinutes || 0);
if (totalIntensity > 0)               msg.garminProps.garmin_intensity_total = totalIntensity;
if (wt && wt.kg)                      msg.garminProps.garmin_weight_kg = wt.kg;
const bp = msg.bpData || null;
if (bp && bp.systolic)                msg.garminProps.garmin_bp_systolic = bp.systolic;
if (bp && bp.diastolic)               msg.garminProps.garmin_bp_diastolic = bp.diastolic;
if (bp && bp.pulse)                   msg.garminProps.garmin_bp_pulse = bp.pulse;
msg.garminProps.garmin_data = true;

msg.dedupId = 'garmin_data';
return msg;

const vaultPath = flow.get('vaultPath') || '/kms/10 PMS/11 Daily Notes';
msg.filename = vaultPath
    + '/' + msg.dateStr.year
    + '/' + msg.dateStr.month
    + '/' + msg.files.dailynotefile;
return msg;

const props = msg.garminProps;
let content = (typeof msg.payload === 'string') ? msg.payload : '';

// Build new property lines
const newEntries = Object.entries(props).map(([k, v]) => k + ': ' + v).join('\n');

const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
if (fmMatch) {
    // Strip existing garmin_* lines, then append updated values
    const existingFm = fmMatch[1].split('\n').filter(l => !l.startsWith('garmin_')).join('\n');
    const newFm = existingFm.trim() ? existingFm + '\n' + newEntries : newEntries;
    msg.payload = content.replace(/^---\n([\s\S]*?)\n---/, '---\n' + newFm + '\n---');
} else {
    // Create frontmatter from scratch
    msg.payload = '---\n' + newEntries + '\n---\n' + content;
}
return [msg, null];
